  async function loadSchemaAndGenerateForm(metaType) {
    const res = await fetch(`/api/schema/${metaType}`);
    const schema = await res.json();
    generateFormFromSchema(schema);
  }

  function generateFormFromSchema(schema) {
    const form = document.getElementById("metaForm");
    form.innerHTML = ''; // Clear form

    for (const [key, value] of Object.entries(schema)) {
      const formGroup = document.createElement("div");
      formGroup.className = "mb-3";

      const label = document.createElement("label");
      label.textContent = key;
      label.className = "form-label";
      formGroup.appendChild(label);

      let input;
      if (Array.isArray(value)) {
        input = document.createElement("textarea");
        input.className = "form-control";
        input.name = key;
        input.rows = 3;
        input.placeholder = "Éléments séparés par des retours à la ligne";
      } else if (typeof value === "object") {
        input = document.createElement("input");
        input.type = "text";
        input.className = "form-control";
        input.name = key;
        input.placeholder = "Valeur (ex: {FR: 'Texte'})";
      } else {
        input = document.createElement("input");
        input.type = "text";
        input.className = "form-control";
        input.name = key;
      }

      formGroup.appendChild(input);
      form.appendChild(formGroup);
    }
  }

  function submitMetaForm() {
    const form = document.getElementById("metaForm");
    const formData = new FormData(form);
    const jsonData = {};

    for (const [key, value] of formData.entries()) {
      if (key === "steps") {
        jsonData[key] = value.split('\n').filter(e => e.trim() !== "").map(e => ({ "FR": e.trim() }));
      } else if (key === "name" || key === "description") {
        jsonData[key] = { "FR": value };
      } else {
        jsonData[key] = value;
      }
    }

    jsonData["type"] = document.getElementById("metaTypeSelect").value;

    fetch('/api/submit', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(jsonData)
    }).then(res => res.json()).then(data => {
      alert("Objet enregistré !");
      console.log("Réponse API :", data);
    });
  }

  document.addEventListener("DOMContentLoaded", () => {
    const defaultType = document.getElementById("metaTypeSelect").value;
    loadSchemaAndGenerateForm(defaultType);

    document.getElementById("metaTypeSelect").addEventListener("change", (e) => {
      loadSchemaAndGenerateForm(e.target.value);
    });
  });
</script>


