  <script>
    async function loadSchema() {
      const type = document.getElementById("meta_type").value;
      const response = await fetch(`/api/schema/${type}`);
      const schema = await response.json();

      const formContainer = document.getElementById("form_fields");
      formContainer.innerHTML = "";

      // Ajout du champ "type" caché
      const hidden = document.createElement("input");
      hidden.type = "hidden";
      hidden.name = "type";
      hidden.value = type;
      formContainer.appendChild(hidden);

      const props = schema.properties || {};
      for (const key in props) {
        if (key === "entrypoint") continue; // on ignore ce champ

        const label = document.createElement("label");
        label.innerText = key;
        label.style.display = "block";

        if (key === "steps") {
          const stepsDiv = document.createElement("div");
          stepsDiv.id = "steps_wrapper";

          const addBtn = document.createElement("button");
          addBtn.type = "button";
          addBtn.innerText = "+ Ajouter une étape";
          addBtn.onclick = () => {
            const input = document.createElement("input");
            input.type = "text";
            input.name = "steps";
            input.required = true;
            input.placeholder = "Étape";
            stepsDiv.appendChild(input);
          };

          label.appendChild(stepsDiv);
          label.appendChild(addBtn);
          formContainer.appendChild(label);
        } else {
          const input = document.createElement("input");
          input.type = "text";
          input.name = key;
          input.required = true;
          input.placeholder = `${key} (FR)`;
          formContainer.appendChild(label);
          formContainer.appendChild(input);
        }
      }
    }

    async function submitForm(event) {
      event.preventDefault();

      const formData = new FormData(event.target);
      const json = {};

      for (const [key, value] of formData.entries()) {
        if (key === "steps") {
          if (!json["steps"]) json["steps"] = [];
          if (value.trim()) json["steps"].push({ FR: value.trim() });
        } else if (key === "description" || key === "name") {
          json[key] = { FR: value.trim() };
        } else {
          json[key] = value.trim();
        }
      }

      const response = await fetch("/api/submit", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify(json),
      });

      const result = await response.json();
      alert("Données envoyées :\n" + JSON.stringify(result.data, null, 2));
    }

    window.addEventListener("DOMContentLoaded", loadSchema);
  </script>
