          input.type = "text";
          input.placeholder = "Entrée en JSON ou texte";
        } else {
          input = document.createElement("input");
          input.type = "text";
        }

        input.name = key;
        input.id = key;
        input.required = true;
        fieldsDiv.appendChild(input);
